var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"흐아아- 팔 떨려.","JPN":"ふああ～腕が震える……","ENG":"Ooh... My arms are shaking.","TWN":"哈啊啊……手臂抖得好厲害。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그치만 견뎠어… 전부 이겼다구.","JPN":"でも耐えた……全部倒した。","ENG":"But I endured it... I won.","TWN":"但是我撐住了……我們贏了。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"패리! 저 잘했죠?","JPN":"パリー！　私、上手くやれましたよね？","ENG":"Parry! Did I do well?","TWN":"悖悖！我做得不錯吧？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"너 이 녀석… 방금 죽을 뻔하고도 웃음이 나와?","JPN":"あなた……下手をすれば死ぬところだったんだよ？　なのになんで笑えるの？","ENG":"Hey... How can you be smiling when you almost died?","TWN":"你這傢伙……剛剛差點就死了，還能笑得出來？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"도망치자고 했잖아. 어째서 그렇게 무리를 한 거야?","JPN":"逃げようって言ったじゃない。なんでそんな無茶をしたのよ。","ENG":"I told you we should run. Why did you act so recklessly?","TWN":"不是說好先逃走的嗎？為什麼要那麼勉強自己？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"도망치면 더 멀어질 뿐이니까요.","JPN":"逃げたら、遠ざかるだけですから。","ENG":"We'll only end up further away if we run away.","TWN":"逃跑的話只會離得更遠。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니는 제가 태어나기 전부터 이런 침식체들과 맞서왔대요.","JPN":"お母さんは、私が生まれる前から侵食体と戦ってきたんですって。","ENG":"Mother said that she fought those kinds of C.O.s since before I was born.","TWN":"媽媽在我出生之前就一直在與這些侵蝕體作戰。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"제 키보다 백 배는 더 큰 침식체도 있는데, 그게 정원의 가장 깊은 안뜰에 있다고 했어요.","JPN":"私より百倍は背が高い侵食体も存在して、それは庭園の一番奥の庭にいるそうです。","ENG":"There are even C.O.s that are a hundred times bigger than me, and they live in the deepest part of the garden's inner yard.","TWN":"有比我高一百倍的侵蝕體，據說它就在花園最深處的內院。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"안뜰에… 이보다 강한 게 있다고?","JPN":"中庭に……さっきのより強いやつがいる……？","ENG":"There are... even stronger C.O.s than this one?","TWN":"內院裡……有比這更強的侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그래서 어머니 혼자 정원 안뜰로 떠나신 거예요. 싸워본 적 없는 절 대신해 침식체들을 막기 위해서요.","JPN":"だからお母さんは1人で中庭に向かったんです。まだ戦った経験のない私のために、侵食体を阻止するために。","ENG":"That's why Mother left for the garden's inner yard by herself. To stop the C.O.s instead of me.","TWN":"所以媽媽才一個人去了花園。為了替代從未戰鬥過的我阻擋侵蝕體。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니 말씀대로라면 저희는 깊이 들어갈수록 더 강한 괴물과 마주치게 되겠죠.","JPN":"お母さんの話どおりなら、奥に行くほど強い化け物に遭遇することになるでしょう。","ENG":"According to Mother's words, the deeper we go in, the stronger the C.O.s we'll encounter.","TWN":"按照媽媽所說，我們越深入就會遇到越強的怪物。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"도망치면서 안전한 길만 찾다보면, 평생이 걸려도 어머닐 만나지 못할 것 같았어요.","JPN":"逃げながら安全な道ばかり探していたら、一生かけてもお母さんに会えない気がするんです。","ENG":"So, I felt like we would never see her if we were to flee and try to look for a safe passageway.","TWN":"如果一直逃跑的話，我覺得一輩子也不會見到她了。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"허… 그래서 싸웠다는 거냐?","JPN":"はあ……だから戦った、と？","ENG":"Huh... So that's why you fought it?","TWN":"嗯……所以你才想戰鬥？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그냥 말만 많은 꼬맹인 줄 알았더니, 내가 너무 얕봤군.","JPN":"よく喋る子どもだと思ったら、どうやらなめていたようだな。","ENG":"I thought you were just a talkative kid, but I guess I underestimated you.","TWN":"原以為你只是個話多的小鬼，看來我太小看你了。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"용감한 것도 좋지만 그렇게 무리해서 뛰어들진 마라.","JPN":"勇気を出すのもいいけど、無理をして敵に飛びかかるんじゃないよ。","ENG":"Being courageous is good and all, but just don't rush in like that.","TWN":"你很勇敢，但不要只顧著衝進去。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아…","JPN":"あ……","ENG":"Ah...","TWN":"啊……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"패리, 제가 멋대로 굴어서 화났어요?","JPN":"パリー、私が勝手なまねをしたから怒ったんですか？","ENG":"Parry, are you mad because of that?","TWN":"悖悖，我自作主張讓你生氣了嗎？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"내가 너한테 화를 왜 내겠냐?","JPN":"私があなたに怒る理由なんてないよ。","ENG":"Why would I be mad at you?","TWN":"我為什麼要生你的氣？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네가 무리하다 다치면 파블린이 슬퍼할 테니까.","JPN":"ただ、あなたが無理をして怪我でもしたら、パブリンが悲しむから。","ENG":"I'm just saying, Pavlin would be sad if you get hurt while being reckless.","TWN":"你要是逞強受傷了，難過的會是帕芙琳。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그럼 널 여기까지 데려온 내가 면목이 없어서 그런다.","JPN":"そうなったらあなたをここまで連れてきた私が、パブリンに合わせる顔がない。それだけだよ。","ENG":"Then, I won't be able to face her after bringing you with me.","TWN":"那樣把你帶到她面前的我只會顯得很沒面子。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"알겠어요. 앞으론 안 다치게 조심할게요!","JPN":"わかりました。これからは怪我しないように気をつけます！","ENG":"All right. I'll be careful not to get hurt from now on!","TWN":"知道了。以後我會小心不受傷的！"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"도착했어요. 여기가 정원의 안뜰로 통하는 세 개의 문 중 두 번째에요.","JPN":"着きました。ここが庭園の中庭に繋がる3つの扉の、2番目です。","ENG":"We're here. This is the second door out of the three that leads to the garden's inner yard.","TWN":"到了。這裡是通往花園內院的三扇門中的第二扇門。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이번엔 덩굴들이 길을 안 막고 있네요.","JPN":"ここはツタに塞がれてなくてよかったですね。","ENG":"At least there aren't vines blocking the path this time.","TWN":"這次藤蔓沒有擋路呢。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"흠…","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};